queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:methodology_id ?cg . ?child a :Methodologies ; p:methodology_id ?cg . ?l p:project_manager_id ?pg . ?parent a :Project_Managers ; p:id ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Project_Managers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?name2 WHERE {
  ?project_managers_methodologies a :Project_Managers_Methodologies .
  ?methodologies a :Methodologies .
  ?project_managers_methodologies p:hasMethodologies ?methodologies .
  ?project_managers a :Project_Managers .
  ?project_managers_methodologies p:hasProject_Managers ?project_managers .
  ?project_managers p:name ?name .
  ?methodologies p:name ?name2 .
} }
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:methodology_id ?cg . ?child a :Methodologies ; p:methodology_id ?cg . ?l p:project_manager_id ?pg . ?parent a :Project_Managers ; p:id ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Project_Managers } }
  FILTER(?nf = ?total)
} }
}
